// A MINIMAL, hand-authored IDML package for the headless harness tests —
// NOT a corpus asset (the fidelity corpus is private / Git-LFS). One
// US-Letter page (Self="usp"), one black Rectangle (Self="urect") with a
// closed 4-anchor PathGeometry. Enough for the engine to parse→build, to
// expose a selectable leaf in the scene tree, to accept an insertFrame on
// the page, and to round-trip setPluginMetadata on the rectangle.
//
// Vendored as base64 so the test has zero external-file / zip-tooling
// dependency and the SDK builds + tests STANDALONE. Regenerate with
// test/fixtures/build-minimal-idml.mjs if the engine's parse contract
// changes (it asserts load on every run, so drift fails loudly).
const MINIMAL_IDML_B64 =
  "";

export const minimalIdml = (): Uint8Array => {
  // `atob` (Node ≥ 16 + browsers) keeps the fixture decode runtime-
  // agnostic — no `Buffer`, so the test needs no @types/node for this.
  const bin = atob(MINIMAL_IDML_B64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
};
